var e=[{id:`L3_1`,type:`dialog`,speaker:`BOX_NPC_GAMECIRCLE_X`,text:{KOREA:`좋아요, 이제 미리네가 세 가지 속성을 다루는 마스터 소드를 꺼내서 순식간에 적을 별 모양으로 베어버릴 거예요!`,JPN:`これからマリが三つの属性を操るマスターソードを抜いて、一瞬で敵を星の形に斬ります！`,ENG:`Okay. So Mi Rinae is going to pull out a master sword that controls all three elements and slash the enemy into a star shape!`,TWN:`看好囉，現在宓璃奈拔出控制三種屬性的寶劍，然後劃星形砍擊敵人！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`BOX_NPC_GAMECIRCLE_X`,face:`UNIT_SERIOUS2`},C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`STAR_GAMECIRCLE_NULL_NULL`,text:{KOREA:`오옷!? 별 모양으로 공격한다고? 진짜가? 멋있을 것 같은데?`,JPN:`おおっ！？　星の形で攻撃するんやな？　マジで？　カッコええやん！`,ENG:`Oh?! A star shape?! Really?! Sounds cool!`,TWN:`哇喔！？劃星形攻擊嗎？真的假的？感覺很酷欸？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`BOX_NPC_GAMECIRCLE_X`,face:`UNIT_SERIOUS2`},C:null,R:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L5_1`,type:`dialog`,speaker:`BOX_NPC_GAMECIRCLE_X`,text:{KOREA:`그 다음, 누나가 말한대로 이펙트가 폭발하면서 적에게 추가적으로 피해를 입히고 그러면서 피버가 터지는 거죠.`,JPN:`その後に、マリさんの言うとおりエフェクトが爆発しながら敵に追加ダメージを与えて、フィーバーになるんです。`,ENG:`Then, the effects you described earlier kicks in, dealing extra damage to the enemies. That’s when the fever mode gets activated.`,TWN:`接下來，就照姊姊說的，效果爆發後額外對敵人造成傷害，然後觸發加成效果。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`BOX_NPC_GAMECIRCLE_X`,face:`UNIT_IDLE`},C:null,R:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L6_1`,type:`dialog`,speaker:`STAR_GAMECIRCLE_NULL_NULL`,text:{KOREA:`오오, 기대되는데? 빨리 함 해봐라!`,JPN:`おお、楽しみやな！　はよやって！`,ENG:`Ooh, I like the sound of it! Go on!`,TWN:`喔喔，好期待喔！快試玩看看唄！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`BOX_NPC_GAMECIRCLE_X`,face:`UNIT_IDLE`},C:null,R:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_LAUGH`}}}}];export{e as default};